import os
import json
import time
import uuid
import math
from typing import Dict, List, Optional, Any
from dataclasses import dataclass, field
from enum import Enum

class CrystalLevel(Enum):
    BASE = 1           # Tetrahedral - 4 sides, 4 facets, 3 points per facet
    COMPOSITE = 2      # Hexagonal - 6 sides, 6-12 facets, 4 points per facet  
    FULL_CONCEPT = 3   # Dodecahedral - 12 sides, 12 facets, 6 points per facet
    QUASI = 4          # Octahedral - 8+8 sides, 16 facets, 8+9th nexus point per facet

@dataclass
class FacetPoint:
    """Individual point within a crystal facet"""
    point_type: str
    value: float = 0.0

    def update_value(self, new_data: str, connections: int = 0):
        """Update point value based on new information"""
        if self.point_type == "emotional":
            self.value = self._calculate_emotional_resonance(new_data)
        elif self.point_type == "polarity":
            self.value = self._calculate_polarity_alignment(new_data)
        elif self.point_type == "associative":
            self.value = min(connections, 20) / 20.0  # Normalize to 0-1
        elif self.point_type == "abstract":
            self.value = self._calculate_abstract_level(new_data)
        elif self.point_type == "temporal":
            self.value = self._calculate_temporal_relevance(new_data)
        elif self.point_type == "cognitive":
            self.value = self._calculate_cognitive_depth(new_data)
        elif self.point_type == "recursive":
            self.value = self._calculate_recursive_complexity(new_data)

    def _calculate_emotional_resonance(self, text: str) -> float:
        """Calculate emotional resonance (0-1)"""
        emotion_words = ['love', 'hate', 'fear', 'joy', 'anger', 'sad', 'happy', 'excited', 'calm']
        text_lower = text.lower()
        resonance = sum(0.1 for word in emotion_words if word in text_lower)
        return min(resonance, 1.0)

    def _calculate_polarity_alignment(self, text: str) -> float:
        """Calculate polarity alignment (-1 to +1)"""
        positive_words = ['good', 'positive', 'beneficial', 'helpful', 'constructive']
        negative_words = ['bad', 'negative', 'harmful', 'destructive', 'problematic']

        text_lower = text.lower()
        positive_score = sum(1 for word in positive_words if word in text_lower)
        negative_score = sum(1 for word in negative_words if word in text_lower)

        if positive_score + negative_score == 0:
            return 0.0

        return (positive_score - negative_score) / (positive_score + negative_score)

    def _calculate_abstract_level(self, text: str) -> float:
        """Calculate abstraction level (0-1)"""
        abstract_indicators = ['concept', 'theory', 'principle', 'abstract', 'general', 'universal']
        text_lower = text.lower()
        abstract_score = sum(0.15 for word in abstract_indicators if word in text_lower)
        return min(abstract_score, 1.0)

    def _calculate_temporal_relevance(self, text: str) -> float:
        """Calculate temporal relevance (0-1)"""
        temporal_words = ['time', 'when', 'before', 'after', 'during', 'future', 'past', 'now']
        text_lower = text.lower()
        temporal_score = sum(0.1 for word in temporal_words if word in text_lower)
        return min(temporal_score, 1.0)

    def _calculate_cognitive_depth(self, text: str) -> float:
        """Calculate cognitive depth (0-1)"""
        cognitive_words = ['think', 'reason', 'understand', 'analyze', 'comprehend', 'logic']
        text_lower = text.lower()
        cognitive_score = sum(0.15 for word in cognitive_words if word in text_lower)
        return min(cognitive_score, 1.0)

    def _calculate_recursive_complexity(self, text: str) -> float:
        """Calculate recursive complexity for quasi-crystals (0-1)"""
        recursive_indicators = ['self', 'recursive', 'meta', 'itself', 'reflection', 'loops']
        text_lower = text.lower()
        recursive_score = sum(0.15 for word in recursive_indicators if word in text_lower)
        return min(recursive_score, 1.0)

@dataclass
class CrystalFacet:
    """Individual facet of a crystal with proper point structure"""
    facet_id: int
    name: str
    description: str = ""
    points: Dict[str, FacetPoint] = field(default_factory=dict)

    def initialize_points(self, level: CrystalLevel):
        """Initialize points based on crystal level as per PDF spec"""
        self.points.clear()

        if level == CrystalLevel.BASE:
            # Level 1: 3 points per facet
            self.points["emotional"] = FacetPoint("emotional")
            self.points["polarity"] = FacetPoint("polarity") 
            self.points["associative"] = FacetPoint("associative")

        elif level == CrystalLevel.COMPOSITE:
            # Level 2: 4 points per facet (adds Abstract Point)
            self.points["emotional"] = FacetPoint("emotional")
            self.points["polarity"] = FacetPoint("polarity")
            self.points["associative"] = FacetPoint("associative")
            self.points["abstract"] = FacetPoint("abstract")

        elif level == CrystalLevel.FULL_CONCEPT:
            # Level 3: 6 points per facet (adds Temporal and Cognitive)
            self.points["emotional"] = FacetPoint("emotional")
            self.points["polarity"] = FacetPoint("polarity")
            self.points["associative"] = FacetPoint("associative")
            self.points["abstract"] = FacetPoint("abstract")
            self.points["temporal"] = FacetPoint("temporal")
            self.points["cognitive"] = FacetPoint("cognitive")

        elif level == CrystalLevel.QUASI:
            # Level 4: 8 points per facet + 9th nexus point
            self.points["emotional"] = FacetPoint("emotional")
            self.points["polarity"] = FacetPoint("polarity")
            self.points["associative"] = FacetPoint("associative")
            self.points["abstract"] = FacetPoint("abstract")
            self.points["temporal"] = FacetPoint("temporal")
            self.points["cognitive"] = FacetPoint("cognitive")
            self.points["recursive"] = FacetPoint("recursive")
            self.points["nexus"] = FacetPoint("nexus")  # 9th central point

    def update_content(self, text: str, connections: int = 0):
        """Update facet content and recalculate all points"""
        self.description = text
        for point in self.points.values():
            point.update_value(text, connections)

    def get_total_resonance(self) -> float:
        """Get total resonance score for this facet"""
        return sum(abs(point.value) for point in self.points.values())

class Crystal:
    """Crystal implementation following PDF specification exactly"""

    def __init__(self, concept: str, level: CrystalLevel = CrystalLevel.BASE):
        self.id = str(uuid.uuid4())
        self.concept = concept
        self.level = level
        self.facets: Dict[int, CrystalFacet] = {}
        self.connections: Dict[str, int] = {}  # Other crystal IDs and connection weights
        self.usage_count = 0
        self.last_accessed = time.time()
        self.formation_timestamp = time.time()

        # Ghost relic distribution tracking
        self.ghost_relic_distribution: Dict[str, float] = {}

        # Internal crystals for quasi-crystals (Level 4)
        self.internal_crystals: List['Crystal'] = []

        self._initialize_structure()

    def _initialize_structure(self):
        """Initialize crystal structure according to PDF specification"""
        facet_counts = {
            CrystalLevel.BASE: 4,         # Tetrahedral: 4 facets
            CrystalLevel.COMPOSITE: 6,    # Hexagonal: 6 facets (can expand to 12)
            CrystalLevel.FULL_CONCEPT: 12, # Dodecahedral: 12 facets
            CrystalLevel.QUASI: 16        # Octahedral: 8 surface + 8 internal = 16 facets
        }

        num_facets = facet_counts[self.level]

        for i in range(num_facets):
            facet_name = self._get_facet_name(i)
            facet = CrystalFacet(facet_id=i, name=facet_name)
            facet.initialize_points(self.level)
            self.facets[i] = facet

    def _get_facet_name(self, facet_id: int) -> str:
        """Get semantic name for facet based on crystal level and position"""
        if self.level == CrystalLevel.BASE:
            names = ["definition", "example", "relation", "evidence"]
            return names[facet_id] if facet_id < len(names) else f"facet_{facet_id}"

        elif self.level == CrystalLevel.COMPOSITE:
            names = ["definition", "example", "relation", "abstract", "context", "operation"]
            return names[facet_id] if facet_id < len(names) else f"composite_facet_{facet_id}"

        elif self.level == CrystalLevel.FULL_CONCEPT:
            names = ["cause", "effect", "condition", "concession", "analogy", "counterexample",
                    "generalization", "particular", "temporal", "spatial", "agent", "patient"]
            return names[facet_id] if facet_id < len(names) else f"concept_facet_{facet_id}"

        elif self.level == CrystalLevel.QUASI:
            if facet_id < 8:
                # Surface facets
                names = ["O_hypothesis", "O_contradiction", "O_analogy", "O_abduction",
                        "O_plan", "O_value", "O_uncertainty", "O_intent"]
                return names[facet_id] if facet_id < len(names) else f"surface_facet_{facet_id}"
            else:
                # Internal recursive facets
                names = ["I_def_check", "I_coherence", "I_causality", "I_evidence",
                        "I_counterfactual", "I_generalize", "I_novelty", "I_bridge"]
                internal_id = facet_id - 8
                return names[internal_id] if internal_id < len(names) else f"internal_facet_{facet_id}"

    def set_facet_content(self, facet_name: str, content: str) -> bool:
        """Set content for a specific facet"""
        # Find facet by name
        target_facet = None
        for facet in self.facets.values():
            if facet.name == facet_name:
                target_facet = facet
                break

        if not target_facet:
            return False

        target_facet.update_content(content, len(self.connections))
        self._update_ghost_relic_distribution()
        return True

    def get_facet_content(self, facet_name: str) -> Optional[str]:
        """Get content from a specific facet"""
        for facet in self.facets.values():
            if facet.name == facet_name:
                return facet.description
        return None

    def touch(self):
        """Record usage of this crystal"""
        self.usage_count += 1
        self.last_accessed = time.time()

    def strengthen_connection(self, other_crystal_id: str, weight: int = 1):
        """Strengthen connection to another crystal"""
        current_weight = self.connections.get(other_crystal_id, 0)
        self.connections[other_crystal_id] = current_weight + weight

        # Update associative points in all facets
        for facet in self.facets.values():
            if "associative" in facet.points:
                facet.points["associative"].update_value("", len(self.connections))

    def check_evolution_criteria(self) -> bool:
        """Check if crystal meets criteria to evolve to next level"""
        if self.level == CrystalLevel.QUASI:
            return False  # Already at highest level

        evolution_thresholds = {
            CrystalLevel.BASE: {
                "associative_min": 5,
                "usage_min": 10,
                "facet_completion": 0.7
            },
            CrystalLevel.COMPOSITE: {
                "associative_min": 10,
                "abstract_min": 0.7,
                "usage_min": 25,
                "facet_completion": 0.8
            },
            CrystalLevel.FULL_CONCEPT: {
                "associative_min": 12,
                "abstract_min": 0.8,
                "temporal_min": 0.8,
                "cognitive_min": 0.8,
                "usage_min": 50,
                "facet_completion": 0.9
            }
        }

        thresholds = evolution_thresholds.get(self.level)
        if not thresholds:
            return False

        # Check associative connections
        if len(self.connections) < thresholds.get("associative_min", 0):
            return False

        # Check usage count
        if self.usage_count < thresholds.get("usage_min", 0):
            return False

        # Check point thresholds
        total_facets = len(self.facets)
        facets_meeting_criteria = 0

        for facet in self.facets.values():
            facet_meets_criteria = True

            for point_type, min_value in thresholds.items():
                if point_type.endswith("_min") and not point_type.startswith("usage") and not point_type.startswith("associative"):
                    point_name = point_type.replace("_min", "")
                    if point_name in facet.points:
                        if facet.points[point_name].value < min_value:
                            facet_meets_criteria = False
                            break

            if facet_meets_criteria and facet.description.strip():
                facets_meeting_criteria += 1

        completion_ratio = facets_meeting_criteria / total_facets
        required_completion = thresholds.get("facet_completion", 0.8)

        return completion_ratio >= required_completion

    def evolve(self) -> bool:
        """Evolve crystal to next level if criteria are met"""
        if not self.check_evolution_criteria():
            return False

        next_level_map = {
            CrystalLevel.BASE: CrystalLevel.COMPOSITE,
            CrystalLevel.COMPOSITE: CrystalLevel.FULL_CONCEPT,
            CrystalLevel.FULL_CONCEPT: CrystalLevel.QUASI
        }

        if self.level not in next_level_map:
            return False

        old_level = self.level
        self.level = next_level_map[self.level]

        # Store existing facet data
        old_facets = {}
        for facet_id, facet in self.facets.items():
            old_facets[facet.name] = facet.description

        # Reinitialize structure for new level
        self._initialize_structure()

        # Restore compatible facet data and upgrade points
        for facet in self.facets.values():
            if facet.name in old_facets:
                facet.update_content(old_facets[facet.name], len(self.connections))

        # Initialize internal crystals for quasi-level
        if self.level == CrystalLevel.QUASI:
            self._initialize_internal_crystals()

        print(f"Crystal '{self.concept}' evolved from {old_level.name} to {self.level.name}")
        return True

    def _initialize_internal_crystals(self):
        """Initialize internal crystals for quasi-level (Level 4)"""
        # Create internal crystals for recursive comprehension
        for i in range(3):  # Start with 3 internal crystals
            internal_concept = f"{self.concept}_internal_{i}"
            internal_crystal = Crystal(internal_concept, CrystalLevel.FULL_CONCEPT)
            self.internal_crystals.append(internal_crystal)

    def _update_ghost_relic_distribution(self):
        """Update ghost relic distribution to connected crystals"""
        total_resonance = sum(facet.get_total_resonance() for facet in self.facets.values())

        if total_resonance > 0 and self.connections:
            distribution_per_connection = total_resonance * 0.1 / len(self.connections)

            for connected_id in self.connections:
                self.ghost_relic_distribution[connected_id] = distribution_per_connection

    def get_crystal_state(self) -> Dict[str, Any]:
        """Get complete state of crystal for analysis"""
        return {
            "id": self.id,
            "concept": self.concept,
            "level": self.level.name,
            "facet_count": len(self.facets),
            "connection_count": len(self.connections),
            "usage_count": self.usage_count,
            "total_resonance": sum(facet.get_total_resonance() for facet in self.facets.values()),
            "evolution_ready": self.check_evolution_criteria(),
            "internal_crystal_count": len(self.internal_crystals),
            "facets": {
                facet.name: {
                    "description": facet.description,
                    "point_values": {name: point.value for name, point in facet.points.items()},
                    "resonance": facet.get_total_resonance()
                }
                for facet in self.facets.values()
            }
        }

class CrystalMemory:
    """Memory system managing crystal network as per PDF specification"""

    def __init__(self, path: str = "crystal_memory.json"):
        self.path = path
        self.crystals: Dict[str, Crystal] = {}
        self.concept_index: Dict[str, str] = {}  # concept_name -> crystal_id
        self.autosave = True
        self.load()

    def ensure_crystal(self, concept: str, initial_content: str = "", level: CrystalLevel = CrystalLevel.BASE) -> str:
        """Ensure crystal exists for concept, create if needed"""
        concept_lower = concept.lower().strip()

        # Check if crystal already exists
        if concept_lower in self.concept_index:
            return self.concept_index[concept_lower]

        # Create new crystal
        crystal = Crystal(concept_lower, level)
        if initial_content:
            crystal.set_facet_content("definition", initial_content)

        self.crystals[crystal.id] = crystal
        self.concept_index[concept_lower] = crystal.id

        if self.autosave:
            self.save()

        return crystal.id

    def get_crystal(self, crystal_id: str) -> Optional[Crystal]:
        """Get crystal by ID"""
        crystal = self.crystals.get(crystal_id)
        if crystal:
            crystal.touch()
        return crystal

    def get_crystal_by_concept(self, concept: str) -> Optional[Crystal]:
        """Get crystal by concept name"""
        concept_lower = concept.lower().strip()
        crystal_id = self.concept_index.get(concept_lower)
        if crystal_id:
            return self.get_crystal(crystal_id)
        return None

    def link_crystals(self, crystal_id1: str, crystal_id2: str, weight: int = 1):
        """Create bidirectional link between crystals"""
        crystal1 = self.crystals.get(crystal_id1)
        crystal2 = self.crystals.get(crystal_id2)

        if crystal1 and crystal2:
            crystal1.strengthen_connection(crystal_id2, weight)
            crystal2.strengthen_connection(crystal_id1, weight)

            if self.autosave:
                self.save()

    def attempt_evolutions(self):
        """Check all crystals for evolution opportunities"""
        evolved_count = 0
        for crystal in self.crystals.values():
            if crystal.evolve():
                evolved_count += 1

        if evolved_count > 0 and self.autosave:
            self.save()

        return evolved_count

    def save(self):
        """Save crystal memory to file"""
        if not self.path:
            return

        data = {
            "metadata": {
                "saved_at": time.time(),
                "crystal_count": len(self.crystals),
                "version": "crystal_ai_pdf_spec"
            },
            "crystals": {},
            "concept_index": self.concept_index
        }

        # Serialize crystals
        for crystal_id, crystal in self.crystals.items():
            data["crystals"][crystal_id] = {
                "concept": crystal.concept,
                "level": crystal.level.name,
                "facets": {},
                "connections": crystal.connections,
                "usage_count": crystal.usage_count,
                "formation_timestamp": crystal.formation_timestamp
            }

            # Serialize facets
            for facet_id, facet in crystal.facets.items():
                data["crystals"][crystal_id]["facets"][facet_id] = {
                    "name": facet.name,
                    "description": facet.description,
                    "points": {name: point.value for name, point in facet.points.items()}
                }

        try:
            with open(self.path, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Error saving crystal memory: {e}")

    def load(self):
        """Load crystal memory from file"""
        if not self.path or not os.path.exists(self.path):
            return

        try:
            with open(self.path, 'r', encoding='utf-8') as f:
                data = json.load(f)

            # Load concept index
            self.concept_index = data.get("concept_index", {})

            # Load crystals
            crystal_data = data.get("crystals", {})
            for crystal_id, crystal_info in crystal_data.items():
                concept = crystal_info.get("concept", "")
                level_name = crystal_info.get("level", "BASE")
                level = CrystalLevel[level_name]

                crystal = Crystal(concept, level)
                crystal.id = crystal_id
                crystal.connections = crystal_info.get("connections", {})
                crystal.usage_count = crystal_info.get("usage_count", 0)
                crystal.formation_timestamp = crystal_info.get("formation_timestamp", time.time())

                # Load facets
                facet_data = crystal_info.get("facets", {})
                for facet_id_str, facet_info in facet_data.items():
                    facet_id = int(facet_id_str)
                    if facet_id in crystal.facets:
                        facet = crystal.facets[facet_id]
                        facet.description = facet_info.get("description", "")

                        # Restore point values
                        point_values = facet_info.get("points", {})
                        for point_name, value in point_values.items():
                            if point_name in facet.points:
                                facet.points[point_name].value = value

                self.crystals[crystal_id] = crystal

        except Exception as e:
            print(f"Error loading crystal memory: {e}")

    def get_memory_stats(self) -> Dict[str, Any]:
        """Get statistics about current crystal memory state"""
        level_counts = {}
        total_resonance = 0
        evolution_ready = 0

        for crystal in self.crystals.values():
            level_name = crystal.level.name
            level_counts[level_name] = level_counts.get(level_name, 0) + 1

            total_resonance += sum(facet.get_total_resonance() for facet in crystal.facets.values())

            if crystal.check_evolution_criteria():
                evolution_ready += 1

        return {
            "total_crystals": len(self.crystals),
            "crystals_by_level": level_counts,
            "total_resonance": total_resonance,
            "evolution_ready": evolution_ready,
            "total_connections": sum(len(crystal.connections) for crystal in self.crystals.values()) // 2
        }

class CrystalAI:
    """Main Crystal AI system interface"""

    def __init__(self, memory_path: str = "crystal_memory.json"):
        self.memory = CrystalMemory(memory_path)
        self.conversation_history = []

    def chat(self, user_input: str) -> str:
        """Main chat interface"""
        user_input = user_input.strip()

        # Record conversation
        self.conversation_history.append({
            "user": user_input,
            "timestamp": time.time()
        })

        # Handle teaching commands
        teaching_response = self._handle_teaching(user_input)
        if teaching_response:
            response = teaching_response
        else:
            # Generate conversational response
            response = self._generate_response(user_input)

        # Record response
        self.conversation_history[-1]["assistant"] = response

        # Attempt crystal evolutions
        evolved = self.memory.attempt_evolutions()
        if evolved > 0:
            response += f" [System evolved {evolved} crystals]"

        return response

    def _handle_teaching(self, user_input: str) -> Optional[str]:
        """Handle teaching commands"""
        import re

        # Define X as Y
        define_match = re.match(r"define\s+(.+?)\s+as\s+(.+)", user_input, re.I)
        if define_match:
            concept, definition = define_match.groups()
            crystal_id = self.memory.ensure_crystal(concept.strip(), definition.strip())
            return f"Defined {concept} as: {definition}"

        # Teach concept.facet: content
        teach_match = re.match(r"teach\s+(\S+)\s*:\s*(.+)", user_input, re.I)
        if teach_match:
            spec, content = teach_match.groups()
            if "." in spec:
                concept, facet_name = spec.split(".", 1)
                crystal = self.memory.get_crystal_by_concept(concept)
                if crystal:
                    if crystal.set_facet_content(facet_name, content):
                        return f"Set {concept}.{facet_name} = {content}"
                    else:
                        return f"Could not set facet '{facet_name}' for {concept}"
                else:
                    crystal_id = self.memory.ensure_crystal(concept)
                    crystal = self.memory.get_crystal(crystal_id)
                    if crystal and crystal.set_facet_content(facet_name, content):
                        return f"Created {concept} and set {facet_name} = {content}"

        return None

    def _generate_response(self, user_input: str) -> str:
        """Generate conversational response using crystal knowledge"""
        # Find relevant crystals
        relevant_crystals = self._find_relevant_crystals(user_input)

        if not relevant_crystals:
            return "I don't have knowledge about that yet. You can teach me by saying 'define [concept] as [definition]'"

        # Use most relevant crystal for response
        best_crystal = relevant_crystals[0]

        # Generate response based on crystal content
        response_parts = []

        # Try to get definition first
        definition = best_crystal.get_facet_content("definition")
        if definition:
            response_parts.append(f"{best_crystal.concept.title()}: {definition}")

        # Add additional relevant facets
        for facet_name in ["example", "relation", "abstract", "cause", "effect"]:
            content = best_crystal.get_facet_content(facet_name)
            if content and content not in response_parts:
                response_parts.append(f"{facet_name.title()}: {content}")
                break  # Only add one additional facet to keep response focused

        if response_parts:
            return ". ".join(response_parts)
        else:
            return f"I know about {best_crystal.concept} but need more information to give you a complete answer."

    def _find_relevant_crystals(self, user_input: str) -> List[Crystal]:
        """Find crystals relevant to user input"""
        input_words = set(user_input.lower().split())
        scored_crystals = []

        for crystal in self.memory.crystals.values():
            score = 0.0

            # Direct concept match
            if crystal.concept in user_input.lower():
                score += 5.0

            # Facet content relevance
            for facet in crystal.facets.values():
                if facet.description:
                    facet_words = set(facet.description.lower().split())
                    overlap = len(input_words.intersection(facet_words))
                    score += overlap * 0.5

            # Recent usage bonus
            hours_since_access = (time.time() - crystal.last_accessed) / 3600.0
            if hours_since_access < 1:
                score += 1.0

            # Crystal level bonus (higher level = more comprehensive)
            level_bonus = {
                CrystalLevel.BASE: 0.0,
                CrystalLevel.COMPOSITE: 0.2,
                CrystalLevel.FULL_CONCEPT: 0.4,
                CrystalLevel.QUASI: 0.6
            }
            score += level_bonus.get(crystal.level, 0.0)

            if score > 0.5:
                scored_crystals.append((crystal, score))

        # Sort by relevance score
        scored_crystals.sort(key=lambda x: x[1], reverse=True)
        return [crystal for crystal, score in scored_crystals[:5]]

    def get_system_status(self) -> Dict[str, Any]:
        """Get comprehensive system status"""
        stats = self.memory.get_memory_stats()

        return {
            "memory_stats": stats,
            "conversation_turns": len(self.conversation_history),
            "system_version": "Crystal AI PDF Specification v1.0"
        }

    def debug_crystal(self, concept: str) -> Dict[str, Any]:
        """Get detailed debug information about a specific crystal"""
        crystal = self.memory.get_crystal_by_concept(concept)
        if not crystal:
            return {"error": f"Crystal not found for concept: {concept}"}

        return crystal.get_crystal_state()


